import java.util.*;
public class Sorted {
    public static void main(String[] args) {
        Map<String, Integer> scores = new TreeMap<>();
        scores.put("Charlie", 85);
        scores.put("Alice",   92);
        scores.put("Bob",     78);
        for (Map.Entry<String, Integer> e : scores.entrySet()) {
            System.out.println(e.getKey() + "=" + e.getValue());
        }
